# scripts/build_dependency_map.py
"""
Build a dependency map for the current train from PR descriptions.
PRs declare dependencies in their description with a structured marker:
  train-depends-on: #138, #140
"""
import re, os, json
import requests

TOKEN = os.environ["GITHUB_TOKEN"]
REPO = os.environ["GITHUB_REPOSITORY"]
HEADERS = {"Authorization": f"Bearer {TOKEN}", "Accept": "application/vnd.github+json"}

def get_pr_dependencies(pr_number: int) -> list[int]:
    """Extract 'train-depends-on:' markers from a PR description."""
    url = f"https://api.github.com/repos/{REPO}/pulls/{pr_number}"
    body = requests.get(url, headers=HEADERS).json().get("body", "") or ""
    match = re.search(r"train-depends-on:\s*([#\d, ]+)", body, re.IGNORECASE)
    if not match:
        return []
    return [int(n.strip("#")) for n in match.group(1).split(",") if n.strip("#").isdigit()]

def build_map(planned_prs: list[int]) -> dict:
    deps = {}
    for pr in planned_prs:
        pr_deps = get_pr_dependencies(pr)
        if pr_deps:
            deps[pr] = pr_deps

    # Check which dependencies are not yet merged
    blocked = {}
    for pr, pr_deps in deps.items():
        unresolved = []
        for dep in pr_deps:
            url = f"https://api.github.com/repos/{REPO}/pulls/{dep}"
            state = requests.get(url, headers=HEADERS).json().get("state")
            if state != "closed":   # closed = merged in GitHub PR API
                unresolved.append(dep)
        if unresolved:
            blocked[pr] = unresolved

    return {"dependencies": deps, "blocked": blocked}

if __name__ == "__main__":
    import sys
    with open(sys.argv[1]) as f:
        scope = json.load(f)
    result = build_map(scope["planned_prs"])
    print(json.dumps(result, indent=2))
    if result["blocked"]:
        print("\nWARNING: The following PRs have unresolved dependencies:")
        for pr, deps in result["blocked"].items():
            print(f"  PR #{pr} blocked on: {deps}")

# scripts/train_status_bot.py
import json, os, requests

SLACK = os.environ["SLACK_RELEASES_WEBHOOK"]

PHASE_MESSAGES = {
    "scope_published": lambda d: {
        "text": f":calendar: *Train {d['train_id']} scope published*",
        "attachments": [{
            "color": "#7dd3fc",
            "fields": [
                {"title": "Planned PRs", "value": str(len(d["planned_prs"])), "short": True},
                {"title": "Freeze", "value": d["freeze_time"][:10], "short": True},
                {"title": "Release Manager", "value": d["release_manager"], "short": True},
                {"title": "Safety Reviewer", "value": d["safety_reviewer"], "short": True},
            ]
        }]
    },
    "freeze_cut": lambda d: {
        "text": f":no_entry: *Train {d['train_id']} — FROZEN*  |  Release branch: `{d['branch']}`",
        "attachments": [{
            "color": "#fbbf24",
            "text": f"Deferred: {list(d.get('deferred_prs', {}).keys())} | "
                    f"In scope: {d['shipped_prs']}"
        }]
    },
    "eval_complete": lambda d: {
        "text": f":test_tube: *Train {d['train_id']} — Eval complete*",
        "attachments": [{
            "color": "#86efac" if d["eval"]["accuracy"] >= 0.95 else "#ef4444",
            "fields": [
                {"title": "Accuracy", "value": f"{d['eval']['accuracy']:.1%}", "short": True},
                {"title": "Safety", "value": f"{d['eval']['safety_pass_rate']:.1%}", "short": True},
                {"title": "Mutation score", "value": f"{d['eval']['mutation_score']:.1%}", "short": True},
                {"title": "Recommendation", "value": d["eval"].get("recommendation", "?"), "short": True},
            ]
        }]
    },
    "deployed": lambda d: {
        "text": f":rocket: *Train {d['train_id']} — DEPLOYED to production*",
        "attachments": [{
            "color": "#86efac",
            "text": f"Shipped {len(d['shipped_prs'])} PRs | Digest: `{d['artifact_digest'][:12]}...`"
        }]
    },
}

def post(phase: str, data: dict) -> None:
    msg_fn = PHASE_MESSAGES.get(phase)
    if not msg_fn:
        return
    requests.post(SLACK, json=msg_fn(data)).raise_for_status()

if __name__ == "__main__":
    import sys
    phase = sys.argv[1]
    data = json.loads(sys.argv[2])
    post(phase, data)
